#include<bits/stdc++.h>
using namespace std;

const int INF = 1e9;

int main() {
    int n , m; 
    cin >> n >> m;

    int dp[n + 1][n + 1];
    for(int i = 1; i <= n; i++) {
        for(int j = 1; j <= n; j++) {
            dp[i][j] = INF;
        }
    }

    for(int i = 0; i < m; i++) {
        int u, v, w;
        cin >> u >> v >> w;
        // Bidirectional edges
        dp[u][v] = w;
        dp[v][u] = w;
    }

    // Set the phase from 1 to N
    for (int k = 1; k <= n; k++) {
        // Update answer for all the pairs of vertices 
        for (int u = 1; u <= n; u++) {
            for (int v = 1; v <= n; v++) {
                dp[u][v] = min(dp[u][v], dp[u][k] + dp[k][v]); 
            }
        }
    }

    for(int u = 1; u <= n; u++) {
        for(int v = 1; v <= n; v++) {
            if(dp[u][v] == INF) 
                cout << -1 << " ";
            else 
                cout << dp[u][v] << " ";
        }
        cout << "\n";
    }

    return 0;
}

