import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        int m = sc.nextInt();

        int INF = 1000000000; // setting infinity as 10^9

        int[][] dp = new int[n + 1][n + 1];
        for (int i = 1; i <= n; i++) {
            for (int j = 1; j <= n; j++) {
                dp[i][j] = INF;
            }
        }

        for (int i = 0; i < m; i++) {
            int u = sc.nextInt();
            int v = sc.nextInt();
            int w = sc.nextInt();
            // Bidirectional edges
            dp[u][v] = w;
            dp[v][u] = w;
        }

        // Set the phase from 1 to N
        for (int k = 1; k <= n; k++) {
            // Update answer for all the pairs of vertices
            for (int u = 1; u <= n; u++) {
                for (int v = 1; v <= n; v++) {
                    dp[u][v] = Math.min(dp[u][v], dp[u][k] + dp[k][v]);
                }
            }
        }

        for (int u = 1; u <= n; u++) {
            for (int v = 1; v <= n; v++) {
                if (dp[u][v] == INF)
                    System.out.print(-1 + " ");
                else
                    System.out.print(dp[u][v] + " ");
            }
            System.out.println();
        }
    }
}

